DECLARE
V_COUNT INTEGER;
BEGIN
SELECT COUNT(TABLE_NAME) INTO V_COUNT from USER_TABLES where TABLE_NAME = '__EFMigrationsHistory';
IF V_COUNT = 0 THEN
Begin
BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"__EFMigrationsHistory" (
    "MigrationId" NVARCHAR2(150) NOT NULL,
    "ProductVersion" NVARCHAR2(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
)';
END;

End;

END IF;
EXCEPTION
WHEN OTHERS THEN
    IF(SQLCODE != -942)THEN
        RAISE;
    END IF;
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"BRIGADA" (
    "ID_BRIGADA" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "NOME" NVARCHAR2(150) NOT NULL,
    "BASE_OPERACIONAL" NVARCHAR2(150) NOT NULL,
    "TELEFONE" NVARCHAR2(20) NOT NULL,
    "ATIVA" NUMBER(1) NOT NULL,
    CONSTRAINT "PK_BRIGADA" PRIMARY KEY ("ID_BRIGADA")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"USUARIO" (
    "ID_USUARIO" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "NOME" NVARCHAR2(150) NOT NULL,
    "EMAIL" NVARCHAR2(150) NOT NULL,
    "SENHA_HASH" NVARCHAR2(255) NOT NULL,
    "PERFIL" NUMBER(10) NOT NULL,
    "ATIVO" NUMBER(1) NOT NULL,
    "DATA_CRIACAO" TIMESTAMP(7) NOT NULL,
    "ULTIMO_LOGIN" TIMESTAMP(7),
    CONSTRAINT "PK_USUARIO" PRIMARY KEY ("ID_USUARIO")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"BRIGADISTA" (
    "ID_BRIGADISTA" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "NOME" NVARCHAR2(150) NOT NULL,
    "MATRICULA" NVARCHAR2(20) NOT NULL,
    "EMAIL" NVARCHAR2(150) NOT NULL,
    "TELEFONE" NVARCHAR2(20) NOT NULL,
    "FUNCAO" NVARCHAR2(50) NOT NULL,
    "ATIVO" NUMBER(1) NOT NULL,
    "DATA_ADMISSAO" TIMESTAMP(7) NOT NULL,
    "ID_BRIGADA" NUMBER(19) NOT NULL,
    CONSTRAINT "PK_BRIGADISTA" PRIMARY KEY ("ID_BRIGADISTA"),
    CONSTRAINT "FK_BRIGADISTA_BRIGADA_ID_BRIGADA" FOREIGN KEY ("ID_BRIGADA") REFERENCES "BRIGADA" ("ID_BRIGADA")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"RECURSO" (
    "ID_RECURSO" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "NOME" NVARCHAR2(150) NOT NULL,
    "TIPO" NUMBER(10) NOT NULL,
    "DISPONIVEL" NUMBER(1) NOT NULL,
    "ID_BRIGADA" NUMBER(19) NOT NULL,
    CONSTRAINT "PK_RECURSO" PRIMARY KEY ("ID_RECURSO"),
    CONSTRAINT "FK_RECURSO_BRIGADA_ID_BRIGADA" FOREIGN KEY ("ID_BRIGADA") REFERENCES "BRIGADA" ("ID_BRIGADA")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"OCORRENCIA" (
    "ID_OCORRENCIA" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "DESCRICAO" NVARCHAR2(500) NOT NULL,
    "LATITUDE" BINARY_DOUBLE NOT NULL,
    "LONGITUDE" BINARY_DOUBLE NOT NULL,
    "STATUS" NUMBER(10) NOT NULL,
    "DATA_ABERTURA" TIMESTAMP(7) NOT NULL,
    "DATA_FINALIZACAO" TIMESTAMP(7),
    "ID_BRIGADISTA" NUMBER(19) NOT NULL,
    "ID_BRIGADA" NUMBER(19) NOT NULL,
    "ID_ALERTA" NUMBER(19),
    CONSTRAINT "PK_OCORRENCIA" PRIMARY KEY ("ID_OCORRENCIA"),
    CONSTRAINT "FK_OCORRENCIA_BRIGADA_ID_BRIGADA" FOREIGN KEY ("ID_BRIGADA") REFERENCES "BRIGADA" ("ID_BRIGADA"),
    CONSTRAINT "FK_OCORRENCIA_BRIGADISTA_ID_BRIGADISTA" FOREIGN KEY ("ID_BRIGADISTA") REFERENCES "BRIGADISTA" ("ID_BRIGADISTA")
)';
END;
/

BEGIN 
EXECUTE IMMEDIATE 'CREATE TABLE 
"REGISTRO_CAMPO" (
    "ID_REGISTRO_CAMPO" NUMBER(19) GENERATED BY DEFAULT ON NULL AS IDENTITY NOT NULL,
    "OBSERVACAO" NVARCHAR2(1000) NOT NULL,
    "URL_FOTO" NVARCHAR2(500) NOT NULL,
    "LATITUDE" BINARY_DOUBLE NOT NULL,
    "LONGITUDE" BINARY_DOUBLE NOT NULL,
    "DATA_REGISTRO" TIMESTAMP(7) NOT NULL,
    "ID_OCORRENCIA" NUMBER(19) NOT NULL,
    CONSTRAINT "PK_REGISTRO_CAMPO" PRIMARY KEY ("ID_REGISTRO_CAMPO"),
    CONSTRAINT "FK_REGISTRO_CAMPO_OCORRENCIA_ID_OCORRENCIA" FOREIGN KEY ("ID_OCORRENCIA") REFERENCES "OCORRENCIA" ("ID_OCORRENCIA")
)';
END;
/

CREATE INDEX "IX_BRIGADISTA_ID_BRIGADA" ON "BRIGADISTA" ("ID_BRIGADA")
/

CREATE INDEX "IX_OCORRENCIA_ID_BRIGADA" ON "OCORRENCIA" ("ID_BRIGADA")
/

CREATE INDEX "IX_OCORRENCIA_ID_BRIGADISTA" ON "OCORRENCIA" ("ID_BRIGADISTA")
/

CREATE INDEX "IX_RECURSO_ID_BRIGADA" ON "RECURSO" ("ID_BRIGADA")
/

CREATE INDEX "IX_REGISTRO_CAMPO_ID_OCORRENCIA" ON "REGISTRO_CAMPO" ("ID_OCORRENCIA")
/

CREATE UNIQUE INDEX "IX_USUARIO_EMAIL" ON "USUARIO" ("EMAIL")
/

